mapper.select:
SELECT c.id ,c.name ,c.image,NULL,COUNT(ufc.character_id) AS followCount FROM user_follow_character ufc INNER JOIN `character` c ON ufc.character_id = c.id WHERE ufc.status = 1
AND ufc.create_time >= #{startTime}
AND ufc.create_time <= #{endTime}
GROUP BY ufc.character_id ORDER BY followCount DESC LIMIT #{limit}
